fn option_unit_qty_add_a(lhs: &OptionUnitQty, rhs: &OptionUnitQty) -> (u64, u64) {
    if !((rhs.tag == 2) || (lhs.tag == 2)) && (lhs.tag != rhs.tag || (lhs.unit != rhs.unit && (lhs.tag & 1) != 0)) {
        panic!()
    }
    if lhs.qty == 0 {
        return (rhs.tag, rhs.unit);
    }
    if rhs.qty == 0 {
        return (lhs.tag, lhs.unit);
    }
    if rhs.tag == 2 {
        (lhs.tag, lhs.unit)
    } else {
        (rhs.tag, rhs.unit)
    }
}

